static __EXT_PHP_RS_MODULE_STARTUP: ::std::sync::Mutex<::std::option::Option<::ext_php_rs::builders::ModuleStartup>> =
    ::std::sync::Mutex::new(::std::option::Option::None);

unsafe extern "C" fn __ext_php_rs_module_startup(ty: i32, mod_num: i32) -> i32 {
    let startup = match __EXT_PHP_RS_MODULE_STARTUP.lock() {
        Ok(mut guard) => guard.take(),
        Err(_) => return 1,
    };
    match startup {
        Some(s) => match s.startup(ty, mod_num) {
            Ok(_) => 0,
            Err(_) => 1,
        },
        None => 1,
    }
}

#[doc(hidden)]
#[unsafe(no_mangle)]
pub extern "C" fn get_module() -> *mut ::ext_php_rs::zend::ModuleEntry {
    static __EXT_PHP_RS_MODULE_ENTRY: ::ext_php_rs::zend::StaticModuleEntry =
        ::ext_php_rs::zend::StaticModuleEntry::new();
    __EXT_PHP_RS_MODULE_ENTRY.get_or_init(|| {
        let builder = ::ext_php_rs::builders::ModuleBuilder::new("tree_sitter_language_pack", "1.10.4")
            .startup_function(__ext_php_rs_module_startup);
        let builder = builder
            .class::<DataAttribute>()
            .class::<DataNode>()
            .class::<Span>()
            .class::<ProcessResult>()
            .class::<FileMetrics>()
            .class::<StructureItem>()
            .class::<CommentInfo>()
            .class::<DocstringInfo>()
            .class::<DocSection>()
            .class::<ImportInfo>()
            .class::<ExportInfo>()
            .class::<SymbolInfo>()
            .class::<Diagnostic>()
            .class::<CodeChunk>()
            .class::<ChunkContext>()
            .class::<PackConfig>()
            .class::<Point>()
            .class::<ByteRange>()
            .class::<Parser>()
            .class::<Tree>()
            .class::<Node>()
            .class::<TreeCursor>()
            .class::<ProcessConfig>()
            .class::<LanguageRegistry>()
            .class::<DownloadManager>()
            .class::<Language>()
            .class::<TreeSitterLanguagePackApi>()
            .class::<DataNodeKind>()
            .class::<StructureKind>()
            .class::<CommentKind>()
            .class::<DocstringFormat>()
            .class::<ExportKind>()
            .class::<SymbolKind>()
            .class::<DiagnosticSeverity>();
        match builder.try_into() {
            Ok((entry, startup)) => {
                *__EXT_PHP_RS_MODULE_STARTUP
                    .lock()
                    .expect("module startup mutex poisoned") = Some(startup);
                entry
            }
            Err(e) => panic!("Failed to build PHP module: {:?}", e),
        }
    })
}
